import "./EmployeeDetails.css";
import { useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { isAdmin, isEmployee } from "../auth";

function EmployeeDetails() {

  const navigate = useNavigate();
  const [employees, setEmployees] = useState([]);

  const loggedUser =
    JSON.parse(localStorage.getItem("loggedInUser")) || null;

  useEffect(() => {
    const stored =
      JSON.parse(localStorage.getItem("employees")) || [];
    setEmployees(stored);
  }, []);

  // ---------------- MATCH EMPLOYEE SAFELY ----------------
  let filteredEmployees = employees;

  if (isEmployee()) {
    const match = employees.find((emp) =>
      String(emp?.empId) === String(loggedUser?.empId) ||    // Primary match
      String(emp?.id) === String(loggedUser?.empId) ||       // Old saved users
      String(emp?.email) === String(loggedUser?.username) || // Login email match
      String(emp?.name)?.toLowerCase() ===
        String(loggedUser?.name)?.toLowerCase()              // Final fallback
    );

    filteredEmployees = match ? [match] : [];
  }

  // ---------------- SAFE NAME DISPLAY ----------------
  const getEmployeeName = (emp) => {
    const first = emp?.firstName?.trim() || "";
    const last = emp?.lastName?.trim() || "";

    if (first || last) return `${first} ${last}`.trim();
    if (emp?.name) return emp.name;

    return "Unnamed";
  };

  return (
    <div className="employee-page">
      <h2 className="employee-title">Manage Employees</h2>

      <div className="employee-actions">
        <input
          type="text"
          placeholder="Search By Employee ID"
          className="search-box"
        />

        {isAdmin() && (
          <button
            className="add-btn"
            onClick={() =>
              navigate("/dashboard/employee-details/add")
            }
          >
            Add New Employee
          </button>
        )}
      </div>

      <table className="employee-table">
        <thead>
          <tr>
            <th>S No</th>
            <th>Name</th>
            <th>DOB</th>
            <th>Department</th>
            {isAdmin() && <th>Action</th>}
          </tr>
        </thead>

        <tbody>
          {filteredEmployees.length > 0 ? (
            filteredEmployees.map((emp, index) => (
              <tr key={emp.id}>
                <td>{index + 1}</td>
                <td>{getEmployeeName(emp)}</td>
                <td>{emp?.dob || "--"}</td>
                <td>{emp?.department || "--"}</td>

                {isAdmin() && (
                  <td className="actions">
                    <button
                      className="view"
                      onClick={() =>
                        navigate(`/dashboard/employee-details/view/${emp.id}`)
                      }
                    >
                      View
                    </button>

                    <button
                      className="edit"
                      onClick={() =>
                        navigate(`/dashboard/employee-details/edit/${emp.id}`)
                      }
                    >
                      Edit
                    </button>

                    <button
                      className="salary"
                      onClick={() =>
                        navigate(
                          `/dashboard/employee-details/salary/add/${emp.id}`
                        )
                      }
                    >
                      Salary
                    </button>

                    <button className="delete">
                      Delete
                    </button>
                  </td>
                )}
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="5" className="no-data">
                No Employees Found
              </td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
}

export default EmployeeDetails;
